mapper.select:
SELECT b.* FROM bookmark_url b
b.user_id = #{userId}
AND (b.title LIKE CONCAT('%', #{query.keyword}, '%') OR b.url LIKE CONCAT('%', #{query.keyword}, '%') OR b.description LIKE CONCAT('%', #{query.keyword}, '%'))
AND b.category_id = #{query.categoryId}
AND EXISTS (SELECT 1 FROM tag_rel WHERE entity_id = b.id AND entity_type = 'bookmark' AND tag_id = #{query.tagId})
ORDER BY b.created_at DESC
